#include <stdio.h>
#include <string.h>
enum { BIG = 1000000007 };

int n;
char s[240];
int slen;
int dp[201][101];
int next[201][2];
int fail[201];

void nextstep(int eo) {
    int i, j;
    for (i = 0; i <= slen; i++) {
        int lp = next[i][0];
        int rp = next[i][1];
        for (j = eo; j <= n; j+=2) {
            int now = dp[i][j];
            if (j < n) {
                int add = dp[lp][j+1] + now;
                dp[lp][j+1] = add < BIG ? add : add - BIG;
            }
            if (j > 0) {
                int add = dp[rp][j-1] + now;
                dp[rp][j-1] = add < BIG ? add : add - BIG;
            }
        }
    }
    for (i = 0; i <= slen; i++) {
        for (j = eo; j <= n; j+=2) {
            dp[i][j] = 0;
        }
    }
    /*for (i=0;i<=slen;i++){
        for (j=0;j<=n;j++){
            printf("%3d,",dp[i][j]);
        }
        puts("");
    }
    puts("");*/
}

int main() {
    scanf("%d", &n);
    scanf(" %202s", s);
    slen = strlen(s);
    int i;
    // build state machine
    fail[0] = fail[1] = 0;
    if (s[0] == '(') {
        next[0][0] = 1;
        next[0][1] = 0;
    }
    else {
        next[0][0] = 0;
        next[0][1] = 1;
    }
    for (i = 1; i < slen; i++) {
        int r = s[i] == ')';
        int f = fail[i];
        next[i][r] = i+1;
        next[i][1-r] = next[f][1-r];
        fail[i+1] = next[f][r];
    }
    next[slen][0] = next[slen][1] = slen;
    dp[0][0] = 1;
    for (i = 0; i < n; i++) {
        nextstep(0);
        nextstep(1);
    }
    printf("%d\n", dp[slen][0]);
    return 0;
}

