const MOD: i64 = 1_000_000_007;

/// Refers external ::MOD.
/// Verified by: https://beta.atcoder.jp/contests/arc099/submissions/2893648
mod mod_int {
    use ::MOD;
    use std::ops::*;
    #[derive(Copy, Clone, Debug, Hash, PartialEq, Eq, PartialOrd, Ord)]
    pub struct ModInt { pub x: i64 }
    impl ModInt {
        fn check_integrity(self) {
            debug_assert!(self.x >= 0);
            debug_assert!(self.x < MOD);
        }
        // x >= 0
        pub fn new(x: i64) -> Self { ModInt { x: x % MOD } }
        #[allow(dead_code)]
        pub fn mul_fast(self, other: Self) -> Self {
            self.check_integrity();
            other.check_integrity();
            ModInt { x: self.x * other.x % MOD }
        }
        #[allow(dead_code)]
        pub fn mul_slow(self, other: Self) -> Self {
            // Naive multiplication in order to avoid overflow
            self.check_integrity();
            other.check_integrity();
            let mut sum = ModInt::new(0);
            let mut cur = self;
            let mut e = other.x;
            if self.x < other.x {
                cur = other;
                e = self.x;
            }
            while e > 0 {
                if e % 2 == 1 {
                    sum = sum + cur;
                }
                cur = cur + cur;
                e /= 2;
            }
            sum
        }
        pub fn pow(self, mut e: i64) -> Self {
            self.check_integrity();
            debug_assert!(e >= 0);
            let mut sum = ModInt::new(1);
            let mut cur = ModInt::new(self.x);
            while e > 0 {
                if e % 2 != 0 {
                    sum = sum * cur;
                }
                cur = cur * cur;
                e /= 2;
            }
            sum
        }
        pub fn inv(self) -> Self { self.pow(MOD - 2) }
    }
    impl Add for ModInt {
        type Output = Self;
        fn add(self, other: Self) -> Self {
            self.check_integrity();
            other.check_integrity();
            let mut sum = self.x + other.x;
            if sum >= MOD { sum -= MOD; }
            ModInt { x: sum }
        }
    }
    impl Sub for ModInt {
        type Output = Self;
        fn sub(self, other: Self) -> Self {
            self.check_integrity();
            other.check_integrity();
            let mut sum = self.x - other.x;
            if sum < 0 { sum += MOD; }
            ModInt { x: sum }
        }
    }
    impl Mul for ModInt {
        type Output = Self;
        fn mul(self, other: Self) -> Self {
            self.mul_fast(other)
        }
    }
    impl ::std::fmt::Display for ModInt {
        fn fmt(&self, f: &mut::std::fmt::Formatter) -> ::std::fmt::Result {
            self.x.fmt(f)
        }
    }
} // mod mod_int

use mod_int::*;

fn solve() {
    let n: usize = get();
    let s: Vec<char> = get_word().chars().collect();
    let m = s.len();
    let mut rev = vec![vec![0; m + 1]; 2];
    for i in 0 .. m {
        let idx = if s[i] == '(' { 0 } else { 1 };
        let opp = if s[i] == '(' { ')' } else { '(' };
        let mut grow = s[0 .. i].to_vec();
        grow.push(opp);
        let mut aa = 0;
        for j in 0 .. i + 1 {
            if grow[j ..] == s[.. i + 1 - j] {
                aa = i + 1 - j;
                break;
            }
        }
        rev[1 - idx][i] = aa;
        rev[idx][i] = i + 1;
    }
    rev[0][m] = m;
    rev[1][m] = m;
    let mut dp = vec![vec![vec![ModInt::new(0); m + 1]; n + 1]; 2 * n + 1];
    dp[0][0][0] = ModInt::new(1);
    for i in 0 .. 2 * n {
        for j in 0 .. n + 1 {
            for k in 0 .. m + 1 {
                if j < n {
                    dp[i + 1][j + 1][rev[0][k]] =
                        dp[i + 1][j + 1][rev[0][k]] + dp[i][j][k];
                }
                if j > 0 {
                    dp[i + 1][j - 1][rev[1][k]] =
                        dp[i + 1][j - 1][rev[1][k]] + dp[i][j][k];
                }
            }
        }
    }
    println!("{}", dp[2 * n][0][m]);
}

fn main() {
    // In order to avoid potential stack overflow, spawn a new thread.
    let stack_size = 104_857_600; // 100 MB
    let thd = std::thread::Builder::new().stack_size(stack_size);
    thd.spawn(|| solve()).unwrap().join().unwrap();
}
